# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

import os
import datetime
import functools

from flask import Flask, request, jsonify, g
import jwt
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key-change-in-production')
app.config['JWT_EXPIRATION_HOURS'] = 24

# In-memory user store (replace with a database in production)
users_db = {}


def create_token(user_id, email):
    """Create a JWT token for a user."""
    payload = {
        'user_id': user_id,
        'email': email,
        'iat': datetime.datetime.utcnow(),
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=app.config['JWT_EXPIRATION_HOURS'])
    }
    token = jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')
    return token


def decode_token(token):
    """Decode and validate a JWT token."""
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def token_required(f):
    """Decorator to protect routes that require authentication."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Check Authorization header
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header.split(' ', 1)[1]

        if not token:
            return jsonify({'error': 'Token is missing', 'message': 'Authorization header with Bearer token is required'}), 401

        payload = decode_token(token)
        if payload is None:
            return jsonify({'error': 'Token is invalid or expired'}), 401

        # Make user info available in the request context
        g.current_user = {
            'user_id': payload['user_id'],
            'email': payload['email']
        }

        return f(*args, **kwargs)
    return decorated


def optional_token(f):
    """Decorator for routes where authentication is optional."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        g.current_user = None
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header.split(' ', 1)[1]
            payload = decode_token(token)
            if payload:
                g.current_user = {
                    'user_id': payload['user_id'],
                    'email': payload['email']
                }
        return f(*args, **kwargs)
    return decorated


# ---- Routes ----

@app.route('/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')
    name = data.get('name', '').strip()

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    if len(password) < 6:
        return jsonify({'error': 'Password must be at least 6 characters'}), 400

    if email in users_db:
        return jsonify({'error': 'User with this email already exists'}), 409

    user_id = str(len(users_db) + 1)
    users_db[email] = {
        'user_id': user_id,
        'email': email,
        'name': name,
        'password_hash': generate_password_hash(password),
        'created_at': datetime.datetime.utcnow().isoformat()
    }

    token = create_token(user_id, email)

    return jsonify({
        'message': 'User registered successfully',
        'token': token,
        'user': {
            'user_id': user_id,
            'email': email,
            'name': name
        }
    }), 201


@app.route('/auth/login', methods=['POST'])
def login():
    """Authenticate a user and return a JWT token."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    user = users_db.get(email)

    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid email or password'}), 401

    token = create_token(user['user_id'], email)

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'user': {
            'user_id': user['user_id'],
            'email': user['email'],
            'name': user['name']
        }
    }), 200


@app.route('/auth/refresh', methods=['POST'])
@token_required
def refresh_token():
    """Refresh the JWT token (requires valid current token)."""
    user = g.current_user
    new_token = create_token(user['user_id'], user['email'])

    return jsonify({
        'message': 'Token refreshed',
        'token': new_token
    }), 200


@app.route('/auth/me', methods=['GET'])
@token_required
def get_current_user():
    """Get the current authenticated user's profile."""
    user_data = users_db.get(g.current_user['email'])
    if not user_data:
        return jsonify({'error': 'User not found'}), 404

    return jsonify({
        'user': {
            'user_id': user_data['user_id'],
            'email': user_data['email'],
            'name': user_data['name'],
            'created_at': user_data['created_at']
        }
    }), 200


@app.route('/auth/change-password', methods=['POST'])
@token_required
def change_password():
    """Change the current user's password."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    current_password = data.get('current_password', '')
    new_password = data.get('new_password', '')

    if not current_password or not new_password:
        return jsonify({'error': 'Current password and new password are required'}), 400

    if len(new_password) < 6:
        return jsonify({'error': 'New password must be at least 6 characters'}), 400

    user = users_db.get(g.current_user['email'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not check_password_hash(user['password_hash'], current_password):
        return jsonify({'error': 'Current password is incorrect'}), 401

    user['password_hash'] = generate_password_hash(new_password)

    return jsonify({'message': 'Password changed successfully'}), 200


# ---- Example Protected Routes ----

@app.route('/api/protected', methods=['GET'])
@token_required
def protected_route():
    """Example of a protected route."""
    return jsonify({
        'message': f'Hello, {g.current_user["email"]}! This is a protected resource.',
        'user': g.current_user
    }), 200


@app.route('/api/public', methods=['GET'])
@optional_token
def public_route():
    """Example of a public route with optional authentication."""
    if g.current_user:
        return jsonify({
            'message': f'Hello, {g.current_user["email"]}! You are authenticated.',
            'authenticated': True
        }), 200
    else:
        return jsonify({
            'message': 'Hello, guest! You can access this without authentication.',
            'authenticated': False
        }), 200


@app.route('/', methods=['GET'])
def index():
    """API info and available endpoints."""
    return jsonify({
        'name': 'Flask JWT Auth API',
        'version': '1.0',
        'endpoints': {
            'POST /auth/register': 'Register a new user (email, password, name)',
            'POST /auth/login': 'Login and get JWT token (email, password)',
            'POST /auth/refresh': 'Refresh JWT token (requires auth)',
            'GET /auth/me': 'Get current user profile (requires auth)',
            'POST /auth/change-password': 'Change password (requires auth)',
            'GET /api/protected': 'Example protected route (requires auth)',
            'GET /api/public': 'Example public route (optional auth)',
        },
        'auth_header_format': 'Authorization: Bearer <token>'
    }), 200


# ---- Error Handlers ----

@app.errorhandler(404)
def not_found(error):
    return jsonify({'error': 'Not found'}), 404


@app.errorhandler(405)
def method_not_allowed(error):
    return jsonify({'error': 'Method not allowed'}), 405


@app.errorhandler(500)
def internal_error(error):
    return jsonify({'error': 'Internal server error'}), 500


if __name__ == '__main__':
    print("Flask JWT Authentication API")
    print("=" * 40)
    print("Endpoints:")
    print("  POST /auth/register  - Register new user")
    print("  POST /auth/login     - Login and get token")
    print("  POST /auth/refresh   - Refresh token")
    print("  GET  /auth/me        - Get user profile")
    print("  POST /auth/change-password - Change password")
    print("  GET  /api/protected  - Protected route example")
    print("  GET  /api/public     - Public route example")
    print("=" * 40)
    app.run(debug=True, host='0.0.0.0', port=5000)